            AddTranslation("When a creature is sacrificed, [creature] gains 1 power until the end of combat.", "有物被祀时，[creature]得1威，至战终。");
            AddTranslation("Sapphire Core", "青核");
            AddTranslation("When [creature] perishes, a Sapphire Vessel is created in its place.", "[creature]亡时，其位生青皿。");
            AddTranslation("Sapphire Heart", "青心");
            AddTranslation("When [creature] perishes, a Sapphire Mox is created in its place.", "[creature]亡时，其位生青玛珂。");
            AddTranslation("Savage Ritual", "野祀");
            AddTranslation("When [creature] is sacrificed, it attacks once before dying.", "[creature]为祀时，先击一次而后死。");
            AddTranslation("Sentriple", "三哨");
