            AddTranslation("When struck, [creature] will transform to or from it's alternate form.", "[creature]被击，则化为其异形，或自异形返之。");
            AddTranslation("Unbalanced Leadership", "偏领");
            AddTranslation("The creature directly to the left of [creature] gains 2 power.", "[creature]左直邻之物得+2威。");
